import{_ as r,a}from"./chunks/dgrid-openclaw-demo.Rr2R33J3.js";import{_ as t,c as o,o as i,ag as n}from"./chunks/framework.S-Qvb3wi.js";const b=JSON.parse('{"title":"AI Gateway 整合教學","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/AI-Gateway-Integrations.md","filePath":"zh-TW/AI-Gateway-Integrations.md"}'),l={name:"zh-TW/AI-Gateway-Integrations.md"};function s(d,e,g,p,h,I){return i(),o("div",null,e[0]||(e[0]=[n('<h1 id="ai-gateway-整合教學" tabindex="-1">AI Gateway 整合教學 <a class="header-anchor" href="#ai-gateway-整合教學" aria-label="Permalink to &quot;AI Gateway 整合教學&quot;">​</a></h1><p>本頁彙整各種常見工具/SDK 的 <strong>DGrid AI Gateway</strong> 整合教學，方便你在同一頁面快速跳轉與查找。</p><h2 id="cursor-覆寫-openai-base-url" tabindex="-1">Cursor（覆寫 OpenAI Base URL） <a class="header-anchor" href="#cursor-覆寫-openai-base-url" aria-label="Permalink to &quot;Cursor（覆寫 OpenAI Base URL）&quot;">​</a></h2><ol><li>取得你的 <code>DGRID_API_KEY</code>（請先看 <a href="/zh-TW/AI-Gateway">AI Gateway</a> 的先決條件）。</li><li>開啟 <strong>Cursor Settings</strong> → <strong>Models</strong>。</li><li>在 <strong>API Keys</strong> 區塊啟用 <strong>Override OpenAI Base URL</strong>。</li><li>將 Base URL 設為： <ul><li><code>https://api.dgrid.ai/v1</code></li></ul></li><li>在 <strong>OpenAI API Key</strong> 貼上你的 <code>DGRID_API_KEY</code>。</li><li>模型名稱使用 DGrid 統一格式（例如：<code>openai/gpt-4o</code>）。</li></ol><p><img src="'+r+'" alt="Cursor settings example"></p><p>完整教學（Blog）：<a href="https://blog.dgrid.ai/posts/2026-02-18/" target="_blank" rel="noreferrer">How to Configure and Use DGrid AI Gateway in Cursor</a></p><h2 id="openai-sdk-node-js-python" tabindex="-1">OpenAI SDK（Node.js / Python） <a class="header-anchor" href="#openai-sdk-node-js-python" aria-label="Permalink to &quot;OpenAI SDK（Node.js / Python）&quot;">​</a></h2><ul><li>請參考：<a href="/zh-TW/AI-Gateway#快速入門">AI Gateway 快速入門</a></li></ul><h2 id="openclaw" tabindex="-1">OpenClaw <a class="header-anchor" href="#openclaw" aria-label="Permalink to &quot;OpenClaw&quot;">​</a></h2><p>你可以在 OpenClaw 中透過 <strong>DGrid AI Gateway</strong> 的 OpenAI 相容端點完成模型連線設定。</p><ol><li>開啟 OpenClaw 的模型或 provider 設定頁面。</li><li>將 API Base URL 設為 <code>https://api.dgrid.ai/v1</code>。</li><li>在 API Key 欄位填入 <code>DGRID_API_KEY</code>。</li><li>選擇一個 DGrid 支援的模型 ID。</li><li>儲存設定後，送出一個測試請求確認連線正常。</li></ol><video controls preload="metadata" style="width:100%;border-radius:12px;margin-top:12px;"><source src="'+a+'" type="video/mp4"> Your browser does not support the video tag. </video><h2 id="blog-整合教學彙整" tabindex="-1">Blog 整合教學彙整 <a class="header-anchor" href="#blog-整合教學彙整" aria-label="Permalink to &quot;Blog 整合教學彙整&quot;">​</a></h2><ul><li><strong>AI as Workspace (AIaW)</strong>：<a href="https://blog.dgrid.ai/posts/2026-03-10/" target="_blank" rel="noreferrer">Step-by-Step Guide: Configure DGrid AI Gateway in AI as Workspace (AIaW)</a></li><li><strong>AnythingLLM</strong>：<a href="https://blog.dgrid.ai/posts/2026-01-30/" target="_blank" rel="noreferrer">Tutorial: Using DGrid AI Gateway with AnythingLLM</a></li><li><strong>Chatbox</strong>：<a href="https://blog.dgrid.ai/posts/2026-03-09/" target="_blank" rel="noreferrer">Step-by-Step Guide: Configure DGrid AI Gateway in Chatbox</a></li><li><strong>Claude Code</strong>：<a href="https://blog.dgrid.ai/posts/2026-03-12/" target="_blank" rel="noreferrer">Use Claude Code with DGrid</a></li><li><strong>Codex CLI</strong>：<a href="https://blog.dgrid.ai/posts/2026-03-23/" target="_blank" rel="noreferrer">Using Codex CLI with DGrid: A Complete Guide</a></li><li><strong>LibreChat</strong>：<a href="https://blog.dgrid.ai/posts/2026-01-28/" target="_blank" rel="noreferrer">Using DGrid with LibreChat: A Step-by-Step Guide</a></li><li><strong>LobeChat</strong>：<a href="https://blog.dgrid.ai/posts/2026-02-09/" target="_blank" rel="noreferrer">Configuring and Utilizing DGrid AI Gateway in LobeChat: A Full Guide</a></li><li><strong>Open WebUI</strong>：<a href="https://blog.dgrid.ai/posts/2026-01-22_2/" target="_blank" rel="noreferrer">Using DGrid AI Gateway with Open WebUI: A Comprehensive Guide</a></li><li><strong>OpenClaw（Agent 平台）</strong>：<a href="https://blog.dgrid.ai/posts/2026-02-02/" target="_blank" rel="noreferrer">Supercharging OpenClaw with DGrid: The Ultimate AI Agent Setup</a></li><li><strong>OpenClaw（免寫程式）</strong>：<a href="https://blog.dgrid.ai/posts/2026-02-27/" target="_blank" rel="noreferrer">Step-by-Step Guide: OpenClaw Installation &amp; DGrid AI Gateway Setup (No Code Required)</a></li><li><strong>Vercel AI SDK</strong>：<a href="https://blog.dgrid.ai/posts/2026-03-26/" target="_blank" rel="noreferrer">How to Use DGrid AI Gateway with the Vercel AI SDK</a></li></ul>',14)]))}const c=t(l,[["render",s]]);export{b as __pageData,c as default};
